import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatCurrency(value: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

export function formatPercent(value: number, digits = 2): string {
  const sign = value >= 0 ? "+" : "";
  return `${sign}${value.toFixed(digits)}%`;
}

export function formatNumber(value: number, digits = 2): string {
  return value.toLocaleString("en-US", {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  });
}

export type Holding = {
  id: string;
  symbol: string;
  shares: number;
  avgCost: number;
};

export type Quote = {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
};

export type HistoryPoint = {
  date: string;
  close: number;
};

export type HistoryRange = "1D" | "1W" | "1M" | "1Y";

export type EnrichedHolding = Holding & {
  quote: Quote | null;
  marketValue: number;
  costBasis: number;
  pl: number;
  plPercent: number;
};

export type PortfolioSnapshot = {
  totalValue: number;
  totalCost: number;
  totalPl: number;
  totalPlPercent: number;
  dayChange: number;
  dayChangePercent: number;
  holdings: EnrichedHolding[];
};

export type TickerItem = {
  label: string;
  value: number;
  change: number;
  changePercent: number;
};

import type { HistoryPoint, HistoryRange, Quote, TickerItem } from "./types";

const COMPANY_NAMES: Record<string, string> = {
  AAPL: "Apple Inc.",
  MSFT: "Microsoft Corp.",
  NVDA: "NVIDIA Corp.",
  GOOGL: "Alphabet Inc.",
  AMZN: "Amazon.com Inc.",
  TSLA: "Tesla Inc.",
  META: "Meta Platforms",
  NFLX: "Netflix Inc.",
};

function hashSymbol(symbol: string): number {
  let hash = 0;
  for (let i = 0; i < symbol.length; i++) {
    hash = (hash << 5) - hash + symbol.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

function daySeed(): number {
  const now = new Date();
  return now.getFullYear() * 10000 + (now.getMonth() + 1) * 100 + now.getDate();
}

export function getMockQuote(symbol: string): Quote {
  const upper = symbol.toUpperCase();
  const base = 40 + (hashSymbol(upper) % 400);
  const seed = daySeed() + hashSymbol(upper);
  const noise = ((seed % 100) - 50) / 500;
  const price = Number((base * (1 + noise)).toFixed(2));
  const change = Number((((seed % 20) - 10) / 10) * (price * 0.01)).toFixed(2));
  const changePercent = Number(((change / price) * 100).toFixed(2));

  return {
    symbol: upper,
    name: COMPANY_NAMES[upper] ?? `${upper} Corp.`,
    price,
    change,
    changePercent,
  };
}

export function getMockQuotes(symbols: string[]): Record<string, Quote> {
  return Object.fromEntries(
    symbols.map((s) => {
      const quote = getMockQuote(s);
      return [quote.symbol, quote];
    })
  );
}

const RANGE_CONFIG: Record<
  HistoryRange,
  { points: number; stepDays: number }
> = {
  "1D": { points: 24, stepDays: 0 },
  "1W": { points: 7, stepDays: 1 },
  "1M": { points: 30, stepDays: 1 },
  "1Y": { points: 52, stepDays: 7 },
};

export function getMockHistory(
  symbol: string,
  range: HistoryRange
): HistoryPoint[] {
  const upper = symbol.toUpperCase();
  const quote = getMockQuote(upper);
  const { points, stepDays } = RANGE_CONFIG[range];
  const data: HistoryPoint[] = [];
  const now = new Date();

  for (let i = points - 1; i >= 0; i--) {
    const date = new Date(now);
    if (range === "1D") {
      date.setHours(date.getHours() - i);
    } else {
      date.setDate(date.getDate() - i * stepDays);
    }

    const wave =
      Math.sin((i + hashSymbol(upper)) * 0.35) * (quote.price * 0.04);
    const drift = ((points - i) / points) * (quote.price * 0.02);
    const close = Number((quote.price - wave + drift).toFixed(2));

    data.push({
      date:
        range === "1D"
          ? date.toLocaleTimeString("en-US", {
              hour: "2-digit",
              minute: "2-digit",
            })
          : date.toLocaleDateString("en-US", {
              month: "short",
              day: "numeric",
            }),
      close,
    });
  }

  return data;
}

export function getMockTickers(): TickerItem[] {
