    { label: "NASDAQ", value: 16742.39, change: -28.55, changePercent: -0.17 },
    { label: "DOW", value: 39127.8, change: 115.3, changePercent: 0.3 },
    { label: "BTC", value: 67420.5, change: 1240.2, changePercent: 1.87 },
    { label: "ETH", value: 3421.8, change: -52.4, changePercent: -1.51 },
    { label: "VIX", value: 13.42, change: -0.38, changePercent: -2.75 },
  ];
}

import type { EnrichedHolding, Holding, PortfolioSnapshot, Quote } from "./types";

export function computePortfolio(
  holdings: Holding[],
  quotes: Record<string, Quote>
): PortfolioSnapshot {
  let totalValue = 0;
  let totalCost = 0;
  let dayChange = 0;

  const enriched: EnrichedHolding[] = holdings.map((h) => {
    const quote = quotes[h.symbol.toUpperCase()] ?? null;
    const price = quote?.price ?? 0;
    const marketValue = price * h.shares;
    const costBasis = h.avgCost * h.shares;
    const pl = marketValue - costBasis;
    const plPercent = costBasis ? (pl / costBasis) * 100 : 0;

    totalValue += marketValue;
    totalCost += costBasis;
    dayChange += (quote?.change ?? 0) * h.shares;

    return {
      ...h,
      quote,
      marketValue,
      costBasis,
      pl,
      plPercent,
    };
  });

  const totalPl = totalValue - totalCost;

  return {
    totalValue,
    totalCost,
    totalPl,
    totalPlPercent: totalCost ? (totalPl / totalCost) * 100 : 0,
    dayChange,
    dayChangePercent: totalValue ? (dayChange / totalValue) * 100 : 0,
    holdings: enriched,
  };
}

import { NextResponse } from "next/server";
import { getMockQuotes } from "@/lib/mock-market";

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const symbolsParam = searchParams.get("symbols") ?? "";
  const symbols = symbolsParam
    .split(",")
    .map((s) => s.trim().toUpperCase())
    .filter(Boolean);

  if (symbols.length === 0) {
    return NextResponse.json({});
  }

  const quotes = getMockQuotes(symbols);
  return NextResponse.json(quotes);
}

import { NextResponse } from "next/server";
import { getMockHistory } from "@/lib/mock-market";
import type { HistoryRange } from "@/lib/types";

const VALID_RANGES: HistoryRange[] = ["1D", "1W", "1M", "1Y"];

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const symbol = (searchParams.get("symbol") ?? "AAPL").toUpperCase();
  const rangeParam = searchParams.get("range") ?? "1M";
  const range = VALID_RANGES.includes(rangeParam as HistoryRange)
    ? (rangeParam as HistoryRange)
    : "1M";

  const history = getMockHistory(symbol, range);
  return NextResponse.json(history);
}

"use client";

import { create } from "zustand";
import { persist } from "zustand/middleware";
import type { Holding } from "@/lib/types";

const DEMO_HOLDINGS: Omit<Holding, "id">[] = [
  { symbol: "AAPL", shares: 25, avgCost: 178.5 },
  { symbol: "MSFT", shares: 15, avgCost: 385.2 },
  { symbol: "NVDA", shares: 10, avgCost: 620.0 },
];

const DEFAULT_WATCHLIST = ["AAPL", "MSFT", "NVDA", "GOOGL", "TSLA"];

function createId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

type PortfolioState = {
  holdings: Holding[];
  watchlist: string[];
  hydrated: boolean;
  addHolding: (holding: Omit<Holding, "id">) => void;
  updateHolding: (id: string, updates: Partial<Omit<Holding, "id">>) => void;
  removeHolding: (id: string) => void;
  addToWatchlist: (symbol: string) => void;
  removeFromWatchlist: (symbol: string) => void;
  setHydrated: (value: boolean) => void;
};

export const usePortfolioStore = create<PortfolioState>()(
  persist(
    (set) => ({
      holdings: DEMO_HOLDINGS.map((h) => ({ ...h, id: createId() })),
      watchlist: DEFAULT_WATCHLIST,
      hydrated: false,
      addHolding: (holding) =>
        set((state) => ({
          holdings: [
            ...state.holdings,
            {
              ...holding,
              symbol: holding.symbol.toUpperCase(),
              id: createId(),
            },
          ],
        })),
      updateHolding: (id, updates) =>
        set((state) => ({
          holdings: state.holdings.map((h) =>
            h.id === id
              ? {
                  ...h,
                  ...updates,
                  symbol: updates.symbol
                    ? updates.symbol.toUpperCase()
                    : h.symbol,
                }
              : h
          ),
        })),
      removeHolding: (id) =>
        set((state) => ({
          holdings: state.holdings.filter((h) => h.id !== id),
        })),
      addToWatchlist: (symbol) =>
        set((state) => {
          const upper = symbol.toUpperCase();
          if (state.watchlist.includes(upper)) return state;
          return { watchlist: [...state.watchlist, upper] };
        }),
      removeFromWatchlist: (symbol) =>
        set((state) => ({
          watchlist: state.watchlist.filter((s) => s !== symbol.toUpperCase()),
        })),
      setHydrated: (value) => set({ hydrated: value }),
    }),
    {
      name: "stock-dashboard-portfolio",
      partialize: (state) => ({
        holdings: state.holdings,
        watchlist: state.watchlist,
      }),
      onRehydrateStorage: () => (state) => {
        state?.setHydrated(true);
      },
    }
  )
);

