"use client";

import { useEffect, useState } from "react";
import {
  Area,
  AreaChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import type { HistoryPoint, HistoryRange } from "@/lib/types";
import { formatCurrency } from "@/lib/utils";

type Props = {
  symbol: string;
};

const RANGES: HistoryRange[] = ["1D", "1W", "1M", "1Y"];

export function StockChart({ symbol }: Props) {
  const [range, setRange] = useState<HistoryRange>("1M");
  const [data, setData] = useState<HistoryPoint[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    fetch(`/api/history?symbol=${symbol}&range=${range}`)
      .then((res) => res.json())
      .then((json: HistoryPoint[]) => setData(json))
      .finally(() => setLoading(false));
  }, [symbol, range]);

  const up =
    data.length > 1 && data[data.length - 1].close >= data[0].close;
  const color = up ? "#34d399" : "#fb7185";

  return (
    <Card className="glass-card border-white/10 shadow-none">
      <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
        <div>
          <CardTitle className="text-xl">{symbol}</CardTitle>
          <p className="text-sm text-zinc-400">Price history</p>
        </div>
        <Tabs
          value={range}
          onValueChange={(v) => setRange(v as HistoryRange)}
        >
          <TabsList className="bg-white/5">
            {RANGES.map((r) => (
              <TabsTrigger key={r} value={r} className="text-xs">
                {r}
              </TabsTrigger>
            ))}
          </TabsList>
        </Tabs>
      </CardHeader>
      <CardContent>
        {loading ? (
          <div className="flex h-[320px] items-center justify-center text-zinc-500">
            Loading chart…
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={320}>
            <AreaChart data={data}>
              <defs>
                <linearGradient id="chartFill" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={color} stopOpacity={0.35} />
                  <stop offset="100%" stopColor={color} stopOpacity={0} />
                </linearGradient>
              </defs>
              <XAxis
                dataKey="date"
                tick={{ fill: "#71717a", fontSize: 11 }}
                axisLine={false}
                tickLine={false}
              />
              <YAxis
                domain={["auto", "auto"]}
                tick={{ fill: "#71717a", fontSize: 11 }}
                axisLine={false}
                tickLine={false}
                tickFormatter={(v) => `$${v}`}
                width={56}
              />
              <Tooltip
                contentStyle={{
                  background: "#18181b",
                  border: "1px solid rgba(255,255,255,0.1)",
                  borderRadius: "8px",
                }}
                labelStyle={{ color: "#a1a1aa" }}
                formatter={(value: number) => [formatCurrency(value), "Close"]}
              />
              <Area
                type="monotone"
                dataKey="close"
                stroke={color}
                fill="url(#chartFill)"
                strokeWidth={2}
              />
            </AreaChart>
          </ResponsiveContainer>
        )}
      </CardContent>
    </Card>
  );
}

