"use client";

import { useState } from "react";
import { Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { usePortfolioStore } from "@/store/portfolio-store";

type Props = {
  mode?: "add" | "edit";
  holdingId?: string;
  initial?: { symbol: string; shares: number; avgCost: number };
  trigger?: React.ReactNode;
  onClose?: () => void;
};

export function AddPositionDialog({
  mode = "add",
  holdingId,
  initial,
  trigger,
  onClose,
}: Props) {
  const addHolding = usePortfolioStore((s) => s.addHolding);
  const updateHolding = usePortfolioStore((s) => s.updateHolding);
  const [open, setOpen] = useState(false);
  const [symbol, setSymbol] = useState(initial?.symbol ?? "");
  const [shares, setShares] = useState(initial?.shares?.toString() ?? "");
  const [avgCost, setAvgCost] = useState(initial?.avgCost?.toString() ?? "");
  const [error, setError] = useState("");

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");

    const sym = symbol.trim().toUpperCase();
    const sh = parseFloat(shares);
    const cost = parseFloat(avgCost);

    if (!sym || sym.length > 6) {
      setError("Enter a valid symbol (1–6 characters).");
      return;
    }
    if (!sh || sh <= 0) {
      setError("Shares must be a positive number.");
      return;
    }
    if (!cost || cost <= 0) {
      setError("Average cost must be a positive number.");
      return;
    }

    if (mode === "edit" && holdingId) {
      updateHolding(holdingId, { symbol: sym, shares: sh, avgCost: cost });
    } else {
      addHolding({ symbol: sym, shares: sh, avgCost: cost });
    }

    setOpen(false);
    setSymbol("");
    setShares("");
    setAvgCost("");
    onClose?.();
  }

  return (
    <Dialog
      open={open}
      onOpenChange={(v) => {
        setOpen(v);
        if (v && initial) {
          setSymbol(initial.symbol);
          setShares(String(initial.shares));
          setAvgCost(String(initial.avgCost));
        }
      }}
    >
      <DialogTrigger asChild>
        {trigger ?? (
          <Button className="gap-2">
            <Plus className="size-4" />
            Add position
          </Button>
        )}
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>
            {mode === "edit" ? "Edit position" : "Add position"}
          </DialogTitle>
          <DialogDescription>
            Track a new holding in your portfolio. Uses mock market prices.
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="symbol">Symbol</Label>
            <Input
              id="symbol"
              placeholder="AAPL"
              value={symbol}
              onChange={(e) => setSymbol(e.target.value.toUpperCase())}
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="shares">Shares</Label>
            <Input
              id="shares"
              type="number"
              min="0"
              step="any"
              placeholder="10"
              value={shares}
              onChange={(e) => setShares(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="avgCost">Average cost ($)</Label>
            <Input
              id="avgCost"
              type="number"
              min="0"
              step="any"
              placeholder="150.00"
              value={avgCost}
              onChange={(e) => setAvgCost(e.target.value)}
            />
          </div>
          {error && <p className="text-sm text-rose-400">{error}</p>}
          <Button type="submit" className="w-full">
            {mode === "edit" ? "Save changes" : "Add to portfolio"}
          </Button>
        </form>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { Pencil, Trash2 } from "lucide-react";
import { AddPositionDialog } from "@/components/portfolio/AddPositionDialog";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { computePortfolio } from "@/lib/portfolio";
import type { Quote } from "@/lib/types";
import { cn, formatCurrency, formatPercent } from "@/lib/utils";
import { usePortfolioStore } from "@/store/portfolio-store";

export function HoldingsTable() {
  const holdings = usePortfolioStore((s) => s.holdings);
  const removeHolding = usePortfolioStore((s) => s.removeHolding);
  const [quotes, setQuotes] = useState<Record<string, Quote>>({});
  const [loading, setLoading] = useState(true);

  const symbols = useMemo(
    () => [...new Set(holdings.map((h) => h.symbol))],
    [holdings]
  );

  useEffect(() => {
    if (symbols.length === 0) {
      setQuotes({});
      setLoading(false);
      return;
    }
    setLoading(true);
    fetch(`/api/quotes?symbols=${symbols.join(",")}`)
      .then((res) => res.json())
      .then(setQuotes)
      .finally(() => setLoading(false));
  }, [symbols]);

  const snapshot = computePortfolio(holdings, quotes);

  if (holdings.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center rounded-2xl border border-dashed border-white/15 bg-white/5 py-16 text-center">
        <p className="text-lg font-medium text-zinc-200">No holdings yet</p>
        <p className="mt-2 max-w-sm text-sm text-zinc-500">
          Add your first position to start tracking portfolio performance.
        </p>
        <div className="mt-6">
          <AddPositionDialog />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-sm text-zinc-400">
          {loading ? "Updating prices…" : `${holdings.length} positions`}
        </p>
        <AddPositionDialog />
      </div>
      <div className="overflow-hidden rounded-2xl border border-white/10">
        <Table>
          <TableHeader>
            <TableRow className="border-white/10 hover:bg-transparent">
              <TableHead>Symbol</TableHead>
              <TableHead className="text-right">Shares</TableHead>
              <TableHead className="text-right">Avg cost</TableHead>
              <TableHead className="text-right">Price</TableHead>
              <TableHead className="text-right">Value</TableHead>
              <TableHead className="text-right">P/L</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {snapshot.holdings.map((h) => {
              const positive = h.pl >= 0;
              return (
                <TableRow key={h.id} className="border-white/10">
                  <TableCell>
                    <div>
                      <span className="font-semibold">{h.symbol}</span>
                      <p className="text-xs text-zinc-500">
                        {h.quote?.name}
                      </p>
                    </div>
                  </TableCell>
                  <TableCell className="text-right font-mono tabular-nums">
                    {h.shares}
                  </TableCell>
                  <TableCell className="text-right font-mono tabular-nums">
                    {formatCurrency(h.avgCost)}
                  </TableCell>
                  <TableCell className="text-right font-mono tabular-nums">
                    {h.quote ? formatCurrency(h.quote.price) : "—"}
                  </TableCell>
                  <TableCell className="text-right font-mono tabular-nums">
                    {formatCurrency(h.marketValue)}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex flex-col items-end gap-1">
                      <span
                        className={cn(
                          "font-mono tabular-nums",
                          positive ? "text-emerald-400" : "text-rose-400"
                        )}
                      >
                        {formatCurrency(h.pl)}
                      </span>
                      <Badge variant={positive ? "success" : "danger"}>
                        {formatPercent(h.plPercent)}
                      </Badge>
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-1">
                      <AddPositionDialog
                        mode="edit"
                        holdingId={h.id}
                        initial={{
                          symbol: h.symbol,
                          shares: h.shares,
                          avgCost: h.avgCost,
                        }}
                        trigger={
                          <Button variant="ghost" size="icon">
                            <Pencil className="size-4" />
                          </Button>
                        }
                      />
                      <Button
                        variant="ghost"
                        size="icon"
                        className="text-rose-400 hover:text-rose-300"
                        onClick={() => removeHolding(h.id)}
                      >
                        <Trash2 className="size-4" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

