"use client";

import { useEffect, useMemo, useState } from "react";
import { PortfolioSummary } from "@/components/dashboard/PortfolioSummary";
import { StockChart } from "@/components/dashboard/StockChart";
import { Watchlist } from "@/components/dashboard/Watchlist";
import { computePortfolio } from "@/lib/portfolio";
import type { Quote } from "@/lib/types";
import { usePortfolioStore } from "@/store/portfolio-store";

export default function DashboardPage() {
  const holdings = usePortfolioStore((s) => s.holdings);
  const watchlist = usePortfolioStore((s) => s.watchlist);
  const [quotes, setQuotes] = useState<Record<string, Quote>>({});
  const [selected, setSelected] = useState("AAPL");

  const allSymbols = useMemo(() => {
    const set = new Set([
      ...watchlist,
      ...holdings.map((h) => h.symbol),
    ]);
    return [...set];
  }, [watchlist, holdings]);

  useEffect(() => {
    if (allSymbols.length === 0) return;
    fetch(`/api/quotes?symbols=${allSymbols.join(",")}`)
      .then((res) => res.json())
      .then(setQuotes);
  }, [allSymbols]);

  useEffect(() => {
    if (watchlist.includes(selected)) return;
    if (watchlist.length > 0) setSelected(watchlist[0]);
    else if (holdings.length > 0) setSelected(holdings[0].symbol);
  }, [watchlist, holdings, selected]);

  const snapshot = computePortfolio(holdings, quotes);

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Dashboard</h1>
        <p className="mt-1 text-zinc-400">
          Track your portfolio and market movers in real time (mock data).
        </p>
      </div>

      <PortfolioSummary snapshot={snapshot} />

      <div className="grid gap-6 lg:grid-cols-3">
        <div className="lg:col-span-2">
          <StockChart symbol={selected} />
        </div>
        <Watchlist
          symbols={watchlist}
          quotes={quotes}
          selected={selected}
          onSelect={setSelected}
        />
      </div>
    </div>
  );
}

